                        activeMarkers.add(marker.position)
                        // set the marker properties, listeners, etc.

                        marker.textLabelBackgroundColor =
                            ContextCompat.getColor(it, R.color.cj_background)
                        marker.textLabelForegroundColor =
                            ContextCompat.getColor(it, R.color.cj_primary)
                        marker.textLabelFontSize = 40
                        marker.setTextIcon(ad.ad.getAdPrice())

                        marker.setAnchor(Marker.ANCHOR_CENTER, Marker.ANCHOR_CENTER)
                        adMarker?.add(marker)
                        marker.setOnMarkerClickListener { selectedMarker, mapView ->
                            binding.mapBottomButton.visibility = View.GONE
                            binding.adCell.visibility = View.VISIBLE
                            binding.osmMapView.controller.setCenter(
                                GeoPoint(
                                    marker.position.latitude,
                                    marker.position.longitude
                                )
                            )
                            if (binding.osmMapView.zoomLevelDouble <= 14) {
                                binding.osmMapView.controller.setZoom(14.0)
                            }

                            if (selectedMarker.textLabelBackgroundColor != ContextCompat.getColor(
                                    it,
                                    R.color.cj_primary
                                )
                            ) {
                                selectedMarker.textLabelBackgroundColor =
                                    ContextCompat.getColor(it, R.color.cj_primary)
                                selectedMarker.textLabelForegroundColor =
                                    ContextCompat.getColor(it, R.color.cj_background)
                            } else {
                                selectedMarker.textLabelBackgroundColor =
                                    ContextCompat.getColor(it, R.color.cj_background)
                                selectedMarker.textLabelForegroundColor =
                                    ContextCompat.getColor(it, R.color.cj_primary)
                                binding.adCell.visibility = View.GONE
                            }
                            selectedMarker.setTextIcon(ad.ad.getAdPrice())

                            previousSelectedMarker?.let { oldSelectedMarker ->
                                if (oldSelectedMarker != selectedMarker) {
                                    oldSelectedMarker.textLabelBackgroundColor =
                                        ContextCompat.getColor(it, R.color.cj_background)
                                    oldSelectedMarker.textLabelForegroundColor =
                                        ContextCompat.getColor(it, R.color.cj_primary)
                                    oldSelectedMarker.setTextIcon(viewModel.previousSelectedMapAd?.ad?.getAdPrice())
                                }
                            }

                            adMarker?.invalidate()
                            binding.osmMapView.overlays.add(adMarker)
                            binding.osmMapView.postInvalidate()
                            previousSelectedMarker = selectedMarker
                            viewModel.previousSelectedMapAd = ad

                            setupAdMapMarkerCell(ad)
                            true
                        }
                    }

                    binding.osmMapView.overlays.add(adMarker)
                    binding.osmMapView.postInvalidate()
                    hideLoadingFragment()
                }
            } else {
                hideLoadingFragment()
            }
        }
